let buffer = context.get('buffer') || Buffer.alloc(0);
buffer = Buffer.concat([buffer, msg.payload]);

let messages = [];

while (buffer.length >= 5) {
    if (buffer[0] !== 0xE0 || buffer[1] !== 0x31) {
        node.warn("Desync, dropping byte");
        buffer = buffer.slice(1);
        continue;
    }

    const data_len = buffer.readUInt16LE(2);
    const total_msg_len = 4 + data_len;

    if (buffer.length < total_msg_len) {
        break;
    }

    const nmi_msg = buffer.slice(0, total_msg_len);
    messages.push({ payload: nmi_msg });

    buffer = buffer.slice(total_msg_len);
}

context.set('buffer', buffer);
if (messages.length > 0) {
    node.send(messages);
}
return null;

// [Full Code for: Decode Alarm (Type 16)]
// This node now has 2 outputs AND uses flow memory
// to only count NEW *ZONE* alarms (rising-edge detection).

// Output 1: Original alarm data (for your UI tables)
// Output 2: Counter trigger (sends a message only on a NEW zone alarm)

const buf = msg.payload;
const msg_type_val = buf[4];
let msg_type_str = "Unknown";

if (msg_type_val === 6) { 
    msg_type_str = "SensorAlarm (Raw)";
} else if (msg_type_val === 16) { 
    msg_type_str = "SensorAlarm (Filtered)";
} else {
    return [null, null]; // Not the right type, stop
}

// --- Get Current States ---
let point_states = flow.get("alarm_point_states") || {};

const device_addr = buf.readUInt16LE(5);
const alarm_point = buf.readUInt16LE(7);

const point_key = `${device_addr}:${alarm_point}`;
const was_alarm = point_states[point_key] || false;

const status_byte = buf[9];
const is_alarm = (status_byte & 0x01) > 0;
const is_tamper = (status_byte & 0x02) > 0;

// --- Update and Save State ---
point_states[point_key] = is_alarm;
flow.set("alarm_point_states", point_states);


// --- Build UI Message (for Output 1) ---
const loc_count = buf.readUInt16LE(10);
let locations = [];
let description = `Point ${alarm_point}`;
let zone_num = null;

if (alarm_point === 1) {
    description = "AuxInput_1";
} else if (alarm_point === 2) {
    description = "AuxInput_2";
} else if (alarm_point >= 3 && alarm_point <= 62) { 
    zone_num = alarm_point - 2;
    description = `Zone_${zone_num}`;
} else if (alarm_point >= 71 && alarm_point <= 74) {
    description = `OptInput_${alarm_point - 70}`;
}

if (loc_count > 0) {
    let offset = 12; 
    for (let i = 0; i < loc_count; i++) {
        if (offset + 2 > buf.length) break; 
        const loc_word = buf.readUInt16LE(offset);
        const distance = loc_word & 0x1FFF;
        const side_val = (loc_word >> 14) & 0x01;
        const active    = (loc_word >> 15) & 0x01;
        locations.push({
            "distance_m": distance,
            "side": (side_val === 0) ? "Side A" : "Side B",
            "active": (active === 1) ? true : false
        });
        offset += 2; 
    }
}

let status = { fill: "grey", shape: "dot", text: "Unknown" };
let status_string = "Unknown";

// --- STATUS TEXT FIX IS HERE ---
if (is_alarm) {
    status.fill = "red";
    status_string = "Alarm";
    if (locations.length > 0 && locations[0].active) {
        const loc = locations[0];
        // This is the line you wanted changed:
        status.text = `ALARM: ${description} @ ${loc.distance_m}m (Device ${device_addr} - ${loc.side})`;
        status_string = `ALARM at ${loc.distance_m}m (Dev ${device_addr} - ${loc.side})`;
    } else {
        status.text = `Dev ${device_addr}: Alarm (Hold): ${description}`;
        status_string = "Alarm (Hold)";
    }
} else if (is_tamper) {
    status.fill = "red";
    status.text = `Dev ${device_addr}: TAMPER: ${description}`;
    status_string = "Tamper/Supervision";
} else if (status_byte === 0) {
    status.fill = "green";
    status.text = `Dev ${device_addr}: Secure: ${description}`;
    status_string = "Secure";
} else {
    status.fill = "grey";
    status.text = `Dev ${device_addr}: Status ${status_byte}: ${description}`;
    status_string = `Status ${status_byte}`;
}

// The generic prefix is no longer needed
node.status(status);
// --- END OF FIX ---

// This is the message for Output 1
let ui_msg = {
    "topic": `NMI/Device_${device_addr}/${description}`,
    "payload": {
        "type": msg_type_str,
        "description": description, 
        "device": device_addr,
        "point_raw": alarm_point,
        "zone": zone_num,
        "status_raw": status_byte,
        "status_string": status_string,
        "alarm": is_alarm,
        "tamper": is_tamper,
        "location_count": loc_count,
        "locations": locations,
        "timestamp": new Date().toISOString()
    }
};

// --- Counter Logic (NOW CHECKS DESCRIPTION) ---
let counter_msg = null;
if (is_alarm && !was_alarm && description.startsWith("Zone_")) {
    counter_msg = { payload: 1 };
    node.log(`NEW ZONE ALARM on ${point_key}, counting.`);
} else if (is_alarm && !was_alarm) {
    node.log(`New non-zone alarm (${description}) on ${point_key}, IGNORING for counter.`);
}

// Return both messages. 
return [ ui_msg, counter_msg ];

// [Full Code for: Decode Pre-Alarm (Type 21)]
const buf = msg.payload;
const device_addr = buf.readUInt16LE(5);
const point_count = buf.readUInt16LE(7);

let pre_alarm_states = flow.get("pre_alarm_point_states") || {};
let new_active_pre_alarms = [];
let messages_to_send = [null, null]; // [ui_msg, counter_msg]
let counter_increment = 0;

for (let i = 0; i < point_count; i++) {
    const point = i + 1;
    const byte_index = 9 + Math.floor(i / 8);
    const bit_index = i % 8;

    if (byte_index >= buf.length) break;

    const byte = buf[byte_index];
    const is_pre_alarm = (byte >> bit_index) & 0x01;

    const point_key = `${device_addr}:${point}`;
    const was_pre_alarm = pre_alarm_states[point_key] || false;

    if (is_pre_alarm) {
        let zone = null;
        let description = `Point ${point}`;
        if (point >= 3) {
            zone = point - 2;
            description = `Zone_${zone}`;
        }
        new_active_pre_alarms.push({ point: point, zone: zone, description: description });

        if (!was_pre_alarm) {
            counter_increment++;
            node.log(`NEW PRE-ALARM on ${point_key}, counting.`);
        }
    }

    pre_alarm_states[point_key] = is_pre_alarm;
}

flow.set("pre_alarm_point_states", pre_alarm_states);

// --- UPDATED STATUS ---
let status_fill = "green";
let status_text = "Pre-Alarm Secure";

if (new_active_pre_alarms.length > 0) {
    status_fill = "yellow";
    status_text = `PRE-ALARM: ${new_active_pre_alarms[0].description}`;
    if (new_active_pre_alarms.length > 1) {
        status_text += ` (+${new_active_pre_alarms.length - 1} more)`;
    }
}

// Add device ID to the status
node.status({ fill: status_fill, shape: "dot", text: `Dev ${device_addr}: ${status_text}` });
// --- END UPDATE ---

messages_to_send[0] = {
    "topic": `NMI/Device_${device_addr}/PreAlarm`,
    "payload": {
        "type": "SensorPreAlarm",
        "device": device_addr,
        "active_pre_alarms": new_active_pre_alarms,
        "timestamp": new Date().toISOString()
    }
};

if (counter_increment > 0) {
    messages_to_send[1] = { payload: counter_increment };
}

return messages_to_send;

// [REVISED] Decode Shunt Status (Type 15)]
const buf = msg.payload;
const devAddr = buf.readUInt16LE(5);
const point_count = buf.readUInt16LE(7);

let all_shunt_states = [];
let shunted_items = [];
let status_text = "Shunt Status Unknown";
let status_fill = "grey";

for (let i = 0; i < point_count; i++) {
    const point = i + 1;
    const byte_index = 9 + Math.floor(i * 2 / 8);
    const bit_index = (i * 2) % 8;

    if (byte_index + 2 > buf.length) break; 

    const word = buf.readUInt16LE(byte_index);
    const state = (word >> bit_index) & 0x03;

    const is_alarm_shunted = (state & 0x01) > 0;
    const is_tamper_shunted = (state & 0x02) > 0;

    let description = `Point_${point}`;
    let zone = null;
    if (point === 1) {
        description = "AuxInput_1";
    } else if (point === 2) {
        description = "AuxInput_2";
    } else if (point >= 3) {
        zone = point - 2;
        description = `Zone_${zone}`;
    }

    all_shunt_states.push({ 
        point: point, 
        zone: zone, 
        description: description, 
        alarm: is_alarm_shunted, 
        tamper: is_tamper_shunted,
        device: devAddr
    });

    if (is_alarm_shunted) {
        shunted_items.push(description.replace("_", " "));
    }
}

if (shunted_items.length > 0) {
    status_fill = "blue";
    status_text = `Shunted: ` + shunted_items.join(', ');
} else {
    status_fill = "green";
    status_text = "Normal (All Points Un-shunted)";
}

// --- UPDATED STATUS ---
node.status({ fill: status_fill, shape: "dot", text: `Dev ${devAddr}: ${status_text}` });
// --- END UPDATE ---

msg.payload = {
    "type": "ShuntStatus",
    "device": devAddr, 
    "shunted_items": shunted_items,
    "all_points": all_shunt_states
};

return msg;

// [REVISED] Decode Device Type (Type 2)
const buf = msg.payload;
let devices = [];
let offset = 5;

while (offset + 10 <= buf.length) {
    const devAddr = buf.readUInt16LE(offset);
    const devType = buf.readUInt16LE(offset + 2);
    const diagAlarms = buf.readUInt16LE(offset + 4);
    const sensorAlarms = buf.readUInt16LE(offset + 6);
    const controlPoints = buf.readUInt16LE(offset + 8);

    let typeName = `Unknown (0x${devType.toString(16)})`;
    if (devType === 0x20F) typeName = "FlexZone-60";
    if (devType === 0x20B) typeName = "FlexZone-20";
    if (devType === 0x20D) typeName = "FlexZone-4";

    // Only add devices with sensor alarms
    if (sensorAlarms > 0) {
        devices.push({
            address: devAddr,
            typeName: typeName,
            sensorAlarms: sensorAlarms,
            controlPoints: controlPoints
        });
    }
    offset += 10;
}

node.status({ fill: "green", shape: "dot", text: `Found ${devices.length} device(s)` });

// Save the list for polling
flow.set("device_list", devices);

// Pass the list to the next node to trigger startup queries
msg.payload = devices;
return msg;

const buf = msg.payload;
const deviceAddr = buf.readUInt16LE(5);
const point_count = buf.readUInt16LE(7);

let in_use_points = [];

for (let i = 0; i < point_count; i++) {
    const point = i + 1;
    const byte_index = 9 + Math.floor(i * 4 / 8); 
    const bit_index = (i * 4) % 8;

    if (byte_index + 1 > buf.length) break; 

    let nibble;
    if (bit_index === 0) { 
        nibble = buf[byte_index] & 0x0F;
    } else { 
        nibble = (buf[byte_index] >> 4) & 0x0F;
    }

    const is_in_use = (nibble >> 3) & 0x01;

    if (is_in_use) {
        let zone = null;
        let description = `Point_${point}`;
        if (point === 1) {
            description = "AuxInput_1";
        } else if (point === 2) {
            description = "AuxInput_2";
        } else if (point >= 3) {
            zone = point - 2;
            description = `Zone_${zone}`;
        }

        in_use_points.push({
            point: point,
            zone: zone,
            description: description,
            alarm_supported: (nibble & 0x01) > 0,
            tamper_supported: (nibble & 0x02) > 0,
            prealarm_supported: (nibble & 0x04) > 0
        });
    }
}

node.status({fill:"green", shape:"dot", text:`Dev ${deviceAddr}: ${in_use_points.length} points in use`});
msg.payload = {
    type: "SensorInUse",
    device: deviceAddr,
    in_use_count: in_use_points.length,
    in_use_points: in_use_points
};
return msg;

// [REVISED] Decode Comm Stat (Type 3)
const buf = msg.payload;
const device_addr = buf.readUInt16LE(5);
const is_connected = buf[7] > 0;
const status_byte = buf[8];

const side_a_fault = (status_byte & 0x01) > 0;
const side_b_fault = (status_byte & 0x02) > 0;

let status_text = "Comm OK";
let status_fill = "green";

if (!is_connected) {
    status_text = "COMM FAIL";
    status_fill = "red";
} else if (side_a_fault || side_b_fault) {
    status_text = "Side Fault";
    status_fill = "yellow";
}

// --- UPDATED STATUS ---
node.status({ fill: status_fill, shape: "dot", text: `Dev ${device_addr}: ${status_text}` });
// --- END UPDATE ---

msg.payload = {
    "type": "CommStatus",
    "device": device_addr,
    "comm_fail": !is_connected,
    "side_a_fault": side_a_fault,
    "side_b_fault": side_b_fault
};

return msg;

// [REVISED] Decode Diag Alarm (Type 4)
const diagMap = {
    1: "EnclosureTamper", 2: "ProgramFlashError", 3: "RAMError",
    4: "ProcessorBootFail", 5: "8VRailFault", 6: "3VRailFault",
    7: "1V8RailFault", 8: "1V2RailFault", 9: "InputPowerFail",
    10: "SideAPowerFault", 11: "SideBPowerFault", 12: "SideASupervision",
    13: "SideBSupervision", 14: "SideAInterference", 15: "SideBInterference",
    16: "ProcessorOffline", 17: "GsmRcvrFault", 18: "GsmRcvrInterference",
    19: "Gsm1_CommFail", 20: "Gsm1_EnclosureTamper", 21: "Gsm1_ProgramFlashError",
    22: "Gsm1_I2CBusFault", 23: "GGsm1_2V7RailFault", 24: "Gsm1_LowPower",
    43: "OptionCardFail"
};

const buf = msg.payload;
const devAddr = buf.readUInt16LE(5);
const point = buf.readUInt16LE(7);
const active = buf[9] > 0;

const name = diagMap[point] || `DiagPoint_${point}`;

// --- UPDATED STATUS ---
node.status({
    fill: active ? "red" : "green",
    shape: "dot",
    text: `Dev ${devAddr}: ${name}: ${active ? 'ACTIVE' : 'Inactive'}`
});
// --- END UPDATE ---

msg.payload = {
    type: "DiagAlarm",
    device: devAddr,
    point: point,
    name: name,
    active: active
};
msg.topic = `NMI/Device_${devAddr}/Diag/${name}`;
return msg;

// [REVISED] Decode Control Status (Type 8)
const outputMap = {
    1: "Relay_1", 2: "Relay_2", 3: "Relay_3", 4: "Relay_4",
    5: "OptRelay_1", 6: "OptRelay_2", 7: "OptRelay_3", 8: "OptRelay_4"
};

const buf = msg.payload;
const devAddr = buf.readUInt16LE(5);
const point = buf.readUInt16LE(7);
const active = buf[9] > 0;

const name = outputMap[point] || `Output_${point}`;

// --- UPDATED STATUS ---
node.status({
    fill: active ? "yellow" : "grey", 
    shape: "dot", 
    text: `Dev ${devAddr}: ${name}: ${active ? 'Active' : 'Inactive'}`
});
// --- END UPDATE ---

msg.payload = {
    type: "ControlStatus",
    device: devAddr,
    point: point,
    name: name,
    active: active
};
msg.topic = `NMI/Device_${devAddr}/Output/${name}`;
return msg;

// [REVISED] Decode Device Summary (Type 19)
const buf = msg.payload;
const devAddr = buf.readUInt16LE(5);
const statusByte = buf[7];

let statusUpdates = [];
statusUpdates.push({
    name: "Summary_CommFail_Mismatch", // Bit 0
    active: (statusByte & 0x01) > 0
});
statusUpdates.push({
    name: "Summary_CommSideFault",     // Bit 1
    active: (statusByte & 0x02) > 0
});
statusUpdates.push({
    name: "Summary_CriticalDiag",      // Bit 2
    active: (statusByte & 0x04) > 0
});
statusUpdates.push({
    name: "Summary_WarningDiag",       // Bit 3
    active: (statusByte & 0x08) > 0
});
statusUpdates.push({
    name: "Summary_EnclosureTamper",   // Bit 4
    active: (statusByte & 0x10) > 0
});

// --- UPDATED STATUS ---
node.status({ fill: "blue", shape: "dot", text: `Dev ${devAddr} Summary: 0x${statusByte.toString(16)}` });
// --- END UPDATE ---

msg.payload = {
    type: "DiagAlarmList",
    device: devAddr,
    statuses: statusUpdates
};
return msg;

// [REVISED] Split Zones and Inputs
// Now splits based on the new description format

const allItems = msg.payload;
let zones = [];
let inputs = [];

for (const item of allItems) {
    if (item.description.includes("Zone")) {
        zones.push(item);
    } else {
        inputs.push(item);
    }
}

return [{ payload: zones }, { payload: inputs }];

// [REVISED] Prep Diags for Table
// This node now reads the state from msg.payload first,
// and defaults to 'true' (Show Active Only) to match the switch.

let show_only_active;

// Check if a state was passed in from the switch
if (typeof msg.payload === 'boolean') {
    // This message came from the switch. Use its payload directly.
    show_only_active = msg.payload;
} else {
    // This message came from a data update. Read from flow context.
    show_only_active = flow.get("diag_show_only_active");
    // And if it's still not set (on startup), apply the default
    if (show_only_active === undefined) {
        show_only_active = true; // <--- THIS IS THE FIX
    }
}

const all_diag_status = flow.get("node_1_diags") || {};
let table = [];

const colors = {
    active: "#ff4d4d",
    inactive: "#00802b"
};

// Loop 1: Iterate over each device ID (e.g., "1", "2")
for (const device_id in all_diag_status) {
    const device_diags = all_diag_status[device_id];

    // Loop 2: Iterate over the alarms for that device
    for (const key in device_diags) {
        // Only show keys that do NOT start with "Summary_"
        if (device_diags.hasOwnProperty(key) && !key.startsWith("Summary_") && !key.startsWith("DiagPoint_")) {
            const active = device_diags[key];

            // --- THIS IS THE FILTER LOGIC ---
            if (!show_only_active || (show_only_active && active === true)) {
                table.push({
                    device: `Device ${device_id}`,
                    description: key.replace(/([A-Z])/g, ' $1').trim(),
                    status: active ? "<b>Active</b>" : "Secure",
                    led: `<font color=\"${active ? colors.active : colors.inactive}\" style=\"font-size: 1.5em; line-height: 1;\">⬤</font>`
                });
            }
        }
    }
}

// Sort the table by device, then by description
table.sort((a, b) => {
    if (a.device < b.device) return -1;
    if (a.device > b.device) return 1;
    return a.description.localeCompare(b.description);
});

msg.payload = table;
return msg;

// [REVISED] Build Shunt Message (Type 14)
// This now uses the device ID from msg.payload
// OUPUT 1: The Shunt command (Type 14)
// OUPUT 2: A new Shunt Status Query (Type 15)

const point = msg.payload.point;
const shunt_state = msg.payload.shunt;
const device = msg.payload.device || 1;

const uMask = 0x01;
const uState = shunt_state ? 0x01 : 0x00;

// --- Output 1: Shunt Command (Type 14) ---
const bufferCmd = Buffer.alloc(11);
bufferCmd[0] = 0xE0;
bufferCmd[1] = 0x31;
bufferCmd.writeUInt16LE(7, 2); // Message length
bufferCmd[4] = 0x0E; // NM_MT_SHUNT
bufferCmd.writeUInt16LE(device, 5); // Use the device ID
bufferCmd.writeUInt16LE(point, 7); // Use the point number
bufferCmd[9] = uMask;
bufferCmd[10] = uState;

if (shunt_state) {
    node.status({ fill: "blue", shape: "dot", text: `Shunting: Dev ${device}, Point ${point}` });
} else {
    node.status({ fill: "grey", shape: "dot", text: `Un-shunting: Dev ${device}, Point ${point}` });
}

// --- Output 2: Shunt Query (Type 15) ---
// We add a 250ms delay to give the NM time to process the command
// before we ask it for the new status.
const bufferQuery = Buffer.alloc(7);
bufferQuery[0] = 0xE0;
bufferQuery[1] = 0x31;
bufferQuery.writeUInt16LE(3, 2); // Data Length
bufferQuery[4] = 0x0F; // NM_MT_SHUNTS
bufferQuery.writeUInt16LE(device, 5);


return [
    { payload: bufferCmd },
    { payload: bufferQuery, "delay": 250 } // Send the query 250ms later
];

// [REVISED] Decode Controls (Type 9)
const outputMap = {
    1: "Relay_1", 2: "Relay_2", 3: "Relay_3", 4: "Relay_4",
    5: "OptRelay_1", 6: "OptRelay_2", 7: "OptRelay_3", 8: "OptRelay_4"
};

const buf = msg.payload;
const devAddr = buf.readUInt16LE(5);
const point_count = buf.readUInt16LE(7);

let all_output_statuses = [];

for (let i = 0; i < point_count; i++) {
    const point = i + 1;
    const byte_index = 9 + Math.floor(i / 8);
    const bit_index = i % 8;

    if (byte_index >= buf.length) break;

    const byte = buf[byte_index];
    const active = (byte >> bit_index) & 0x01;

    const name = outputMap[point] || `Output_${point}`;

    all_output_statuses.push({
        type: "ControlStatus",
        device: devAddr,
        point: point,
        name: name,
        active: active > 0
    });
}

// --- UPDATED STATUS ---
node.status(`Dev ${devAddr}: Full control status for ${point_count} points`);
// --- END UPDATE ---

msg.payload = {
    type: "ControlStatusList",
    device: devAddr,
    statuses: all_output_statuses
};
return msg;

// [REVISED] Prep Outputs for Table
// This node now reads the compound key and adds device/point to the row

const outputs = flow.get("node_1_outputs");
let table = [];

const colors = {
    active: "#00802b",
    inactive: "#808080"
};

const button_style = "padding: 4px 10px; border-radius: 4px; color: white; width: 100%; box-sizing: border-box; text-align: center; font-size: 0.9em; cursor: pointer;";

// This map is still needed to get the point number from the name
const outputMap = {
    "Relay_1": 1,
    "Relay_2": 2,
    "Relay_3": 3,
    "Relay_4": 4,
    "OptRelay_1": 5,
    "OptRelay_2": 6,
    "OptRelay_3": 7,
    "OptRelay_4": 8
};

for (const key in outputs) {
    if (outputs.hasOwnProperty(key)) {
        const active = outputs[key];

        // Split the compound key "device:name"
        const [device_id, name] = key.split(':');
        const point_num = outputMap[name] || parseInt(name.split('_')[1]) || 0;

        table.push({
            description: `Dev ${device_id} - ${name.replace("_", " ")}`,
            status: active ? "Active" : "Inactive",
            led: `<font color=\"${active ? colors.active : colors.inactive}\" style=\"font-size: 1.5em; line-height: 1;\">⬤</font>`,
            _point: point_num,
            _device: parseInt(device_id), // Add device ID to row
            _status: active ? "active" : "inactive",
            action_button: active ? `<div style=\"${button_style} background-color: ${colors.active};\">Deactivate</div>` : `<div style=\"${button_style} background-color: ${colors.inactive};\">Activate</div>`
        });
    }
}

// Sort the table by device, then point
table.sort((a, b) => {
    if (a._device < b._device) return -1;
    if (a._device > b._device) return 1;
    return a._point - b._point;
});

msg.payload = table;
return msg;

