// [REVISED] Build Control Message (Type 8)
// This now uses the device ID from msg.payload

const point = msg.payload.point;
const active = msg.payload.active;
const device = msg.payload.device; // Get the device ID

const buffer = Buffer.alloc(10);
buffer[0] = 0xE0;
buffer[1] = 0x31;
buffer.writeUInt16LE(6, 2); // Message length
buffer[4] = 0x08; // NM_MT_CONTROL

buffer.writeUInt16LE(device, 5); // Use the device ID
buffer.writeUInt16LE(point, 7); // Use the point number

buffer[9] = active ? 0x01 : 0x00; 

node.status({
    fill: active ? "green" : "grey",
    shape: "dot",
    text: `Setting Dev ${device} Point ${point} to ${active ? 'Active' : 'Inactive'}`
});

msg.payload = buffer;
return msg;

// [REVISED] Consolidated Startup Queries
// Sends only the device discovery message.
// The response to this will trigger all other queries.

const buffer = Buffer.alloc(7);
buffer[0] = 0xE0;
buffer[1] = 0x31;
buffer.writeUInt16LE(3, 2); // Data Length
buffer[4] = 0x02; // NM_MT_DEVC_TYPE
buffer.writeUInt16LE(0xFFFF, 5); // 0xFFFF = All Devices
msg.payload = buffer;

return msg;

// [REVISED] Consolidated Polling
// This now loops through the saved device list

const devices = flow.get("device_list") || [];
if (devices.length === 0) {
    node.warn("Polling: No device list found.");
    return null;
}

function buildQuery(msgType, deviceId) {
    const buffer = Buffer.alloc(7);
    buffer[0] = 0xE0;
    buffer[1] = 0x31;
    buffer.writeUInt16LE(3, 2);
    buffer[4] = msgType;
    buffer.writeUInt16LE(deviceId, 5);
    return { payload: buffer };
}

function buildHeartbeat() {
    const buffer = Buffer.alloc(7);
    buffer[0] = 0xE0;
    buffer[1] = 0x31;
    buffer.writeUInt16LE(3, 2);
    buffer[4] = 0x01;
    buffer[5] = 0xAA;
    buffer[6] = 0xFF;
    return { payload: buffer };
}

let count = context.get("pollCounter") || 0;
count++;

for (const device of devices) {
    const devAddr = device.address;

    // --- Every 10 seconds (Runs on every tick) ---
    node.send(buildQuery(0x0F, devAddr)); // 1. Get Shunt Status (Type 15)

    // --- Every 20 seconds (Runs on tick 2, 4, 6...) ---
    if (count % 2 === 0) { // <--- CHANGED FROM 3 TO 2
        node.send(buildQuery(0x03, devAddr)); // 2. Get Comm Status (Type 3)
        node.send(buildQuery(0x13, devAddr)); // 3. Get Device Summary (Type 19)
        node.send(buildQuery(0x09, devAddr)); // 4. Get All Controls (Type 9)
        node.send(buildQuery(0x05, devAddr)); // 5. Get All Diag Alarms (Type 5)
    }
}

// Send one heartbeat
if (count % 2 === 0) { // <--- CHANGED FROM 3 TO 2
    node.send(buildHeartbeat());
    node.log(`Polling ${devices.length} device(s)...`);
}

if (count >= 2) { // <--- CHANGED FROM 3 TO 2
    count = 0;
}
context.set("pollCounter", count);

return null;

// [REVISED] Decode Diag Alarms (Type 5)
const diagMap = {
    1: "EnclosureTamper", 2: "ProgramFlashError", 3: "RAMError",
    4: "ProcessorBootFail", 5: "8VRailFault", 6: "3VRailFault",
    7: "1V8RailFault", 8: "1V2RailFault", 9: "InputPowerFail",
    10: "SideAPowerFault", 11: "SideBPowerFault", 12: "SideASupervision",
    13: "SideBSupervision", 14: "SideAInterference", 15: "SideBInterference",
    16: "ProcessorOffline", 17: "GsmRcvrFault", 18: "GsmRcvrInterference",
    19: "Gsm1_CommFail", 20: "Gsm1_EnclosureTamper", 21: "Gsm1_ProgramFlashError",
    22: "Gsm1_I2CBusFault", 23: "GGsm1_2V7RailFault", 24: "Gsm1_LowPower",
    43: "OptionCardFail"
};

const buf = msg.payload;
const devAddr = buf.readUInt16LE(5);
const point_count = buf.readUInt16LE(7);

let statusUpdates = []; 

for (let i = 0; i < point_count; i++) {
    const point = i + 1;
    const byte_index = 9 + Math.floor(i / 8);
    const bit_index = i % 8;

    if (byte_index >= buf.length) break;

    const byte = buf[byte_index];
    const active = (byte >> bit_index) & 0x01;

    const name = diagMap[point] || `DiagPoint_${point}`;

    statusUpdates.push({
        name: name,
        active: active > 0
    });
}

// --- UPDATED STATUS ---
node.status(`Dev ${devAddr}: ${point_count} diag points processed`);
// --- END UPDATE ---

msg.payload = {
    type: "DiagAlarmList",
    device: devAddr,
    statuses: statusUpdates
};
return msg;

// [function] Decode Control In-Use (Type 25)
// This decodes which control points are available.

const buf = msg.payload;
const devAddr = buf.readUInt16LE(5);
const point_count = buf.readUInt16LE(7);

// This is the same map from your output nodes
const outputMap = {
    1: "Relay_1",
    2: "Relay_2",
    3: "Relay_3",
    4: "Relay_4",
    5: "OptRelay_1",
    6: "OptRelay_2",
    7: "OptRelay_3",
    8: "OptRelay_4"
};

let in_use_controls = [];

// Loop through each point in the bitmask
for (let i = 0; i < point_count; i++) {
    const point = i + 1;
    const byte_index = 9 + Math.floor(i / 8);
    const bit_index = i % 8;

    if (byte_index >= buf.length) break;

    const byte = buf[byte_index];
    const isInUse = (byte >> bit_index) & 0x01;

    if (isInUse) {
        const name = outputMap[point] || `Output_${point}`;
        in_use_controls.push({
            point: point,
            name: name
        });
    }
}

node.status(`${in_use_controls.length} controls in use`);

msg.payload = {
    type: "ControlInUse",
    device: devAddr,
    in_use_controls: in_use_controls
};

return msg;

// [REVISED] Decode Filter Alarms (Type 17)
// This node now adds the device ID to every point object.

const buf = msg.payload;
const devAddr = buf.readUInt16LE(5); // <-- FIX: Read the Device ID
const point_count = buf.readUInt16LE(7);

let all_point_statuses = []; 
let point = 1;

for (let byte_index = 9; byte_index < buf.length; byte_index++) {
    const byte = buf[byte_index];

    for (let i = 0; i < 4; i++) { 
        if (point > point_count) break;

        const state = (byte >> (i * 2)) & 0x03; 
        const is_alarm = (state & 0x01) > 0;
        const is_tamper = (state & 0x02) > 0;

        let description = `Point ${point}`;
        let zone_num = null;
        if (point === 1) {
            description = "AuxInput_1";
        } else if (point === 2) {
            description = "AuxInput_2";
        } else if (point >= 3 && point <= 62) {
            zone_num = point - 2;
            description = `Zone_${zone_num}`;
        } else if (point >= 71 && point <= 74) {
            description = `OptInput_${point - 70}`;
        }

        let status_string = "Secure";
        if (is_alarm) {
            status_string = "Alarm (Hold)"; 
        } else if (is_tamper) {
            status_string = "Tamper/Supervision";
        }

        all_point_statuses.push({
            "type": "SensorAlarm (Filtered)", 
            "description": description,
            "device": devAddr, // <-- FIX: Add the Device ID here
            "point_raw": point,
            "zone": zone_num,
            "status_raw": state,
            "status_string": status_string,
            "alarm": is_alarm,
            "tamper": is_tamper,
            "location_count": 0,
            "locations": [],
            "timestamp": new Date().toISOString()
        });

        point++; 
    }
    if (point > point_count) break;
}

node.status(`${all_point_statuses.length} points processed for Dev ${devAddr}`);

msg.payload = {
    type: "FilteredAlarmList",
    device: devAddr, // Add device to top level for consistency
    points: all_point_statuses
};

return msg;

