// Calculates distance between {x, y} points
function getDistance(p1, p2) {
    const dx = p1.x - p2.x;
    const dy = p1.y - p2.y;
    return Math.sqrt(dx * dx + dy * dy);
}

// Main function to find (x, y) from a meter value
function meterToCoords(meterValue, zoneData) {
    if (!zoneData || !zoneData.path_points || zoneData.path_points.length < 2 || zoneData.path_points[0] === null) {
        return null; // Not enough data to interpolate
    }

    const path_points = zoneData.path_points;
    const meter_start = zoneData.meter_start;
    const meter_end = zoneData.meter_end;
    const total_meter_length = meter_end - meter_start;

    if (total_meter_length <= 0) {
        return { x: path_points[0].x, y: path_points[0].y }; // No length, return start
    }

    // 1. Calculate Total Pixel Length
    let total_pixel_length = 0;
    let cumulative_pixel_lengths = [0];
    for (let i = 1; i < path_points.length; i++) {
        total_pixel_length += getDistance(path_points[i - 1], path_points[i]);
        cumulative_pixel_lengths.push(total_pixel_length);
    }

    if (total_pixel_length === 0) {
         return { x: path_points[0].x, y: path_points[0].y };
    }

    // 2. Find target pixel distance
    const meter_ratio = (meterValue - meter_start) / total_meter_length;
    const target_pixel_distance = meter_ratio * total_pixel_length;

    // 3. Find the correct path segment
    for (let i = 1; i < path_points.length; i++) {
        const p_start = path_points[i - 1];
        const p_end = path_points[i];
        const segment_start_px = cumulative_pixel_lengths[i - 1];
        const segment_end_px = cumulative_pixel_lengths[i];

        if (target_pixel_distance >= segment_start_px && target_pixel_distance <= segment_end_px) {
            // This is the segment!
            const segment_length_px = segment_end_px - segment_start_px;
            if (segment_length_px === 0) {
                return { x: p_start.x, y: p_start.y };
            }

            const segment_ratio = (target_pixel_distance - segment_start_px) / segment_length_px;

            // Interpolate coordinates
            const x = p_start.x + (p_end.x - p_start.x) * segment_ratio;
            const y = p_start.y + (p_end.y - p_start.y) * segment_ratio;
            return { x: x, y: y };
        }
    }

    // Fallback: if meter value is outside range, clamp to start or end
    if (meterValue <= meter_start) return { x: path_points[0].x, y: path_points[0].y };
    return { x: path_points[path_points.length - 1].x, y: path_points[path_points.length - 1].y };
}


