const meter_start = parseNum(data.meter_start);
const meter_end = parseNum(data.meter_end);
const total_meter_length = meter_end - meter_start;

if (!path_points || path_points.length < 2) {
    node.warn("Path needs at least 2 points to save.");
    return null;
}

// --- 1. Calculate Total Pixel Length of the Drawn Path ---
let total_pixel_length = 0;
let cumulative_pixel_lengths = [0]; // Start at 0
for (let i = 1; i < path_points.length; i++) {
    const segment_distance = getDistance(path_points[i - 1], path_points[i]);
    total_pixel_length += segment_distance;
    cumulative_pixel_lengths.push(total_pixel_length);
}

