    // Check for division by zero
    if (total_pixel_length === 0) {
        meter_position = meter_start;
    } else {
        const meter_ratio = pixel_distance / total_pixel_length;
        meter_position = meter_start + (meter_ratio * total_meter_length);
    }

    // Create the SQL (VALUES) string including the device_id
    value_strings.push(
        `(${device_id}, '${zone_id}', ${Math.round(meter_position)}, ${point.x}, ${point.y})`
    );
}

